import React, { useEffect } from 'react';
import { Linking } from 'react-native';
import { CommonActions, useNavigation } from '@react-navigation/native';

const DeepLinkHandler = ({ children }) => {
  const navigation = useNavigation();

  const handleDeepLink = (url) => {
    if (!url) return;

    const [scheme, path] = url.split('://');

    if (scheme !== 'myapp') {
      console.log('Unsupported deep link scheme:', scheme);
      return;
    }

    const [screen, param] = path.split('/');

    switch (screen) {
      case 'profile':
        if (param) {
          navigation.dispatch(
            CommonActions.navigate({
              name: 'ProfileScreen',
              params: { userId: param },
            })
          );
        }
        break;
      case 'payment':
        if (param === 'confirm') {
          navigation.dispatch(
            CommonActions.navigate({
              name: 'PaymentConfirmationScreen',
            })
          );
        }
        break;
      case 'home':
        navigation.dispatch(
          CommonActions.navigate({
            name: 'HomeScreen',
          })
        );
        break;
      default:
        console.log('Unknown deep link screen:', screen);
        navigation.dispatch(
          CommonActions.navigate({
            name: 'HomeScreen', // Fallback to home screen
          })
        );
        break;
    }
  };

  useEffect(() => {
    // Initial check for deep link when the app is launched from a deep link
    Linking.getInitialURL().then(url => {
      if (url) {
        handleDeepLink(url);
      }
    });

    // Listen for deep links when the app is already running
    const subscription = Linking.addEventListener('url', ({ url }) => {
      handleDeepLink(url);
    });

    return () => {
      // Clean up the event listener
      subscription.remove();
    };
  }, [navigation]);

  return <>{children}</>;
};

export default DeepLinkHandler;

